// Accepts either:
//   type: 'recording'   + file_url (video URL → AssemblyAI)
//   type: 'transcript'  + transcript_url (text file URL → fetch then store)

const body = $input.item.json.body || $input.item.json;

const type = body.type || 'recording';
const title = body.title || 'Untitled';
const category = body.category || 'General';
const recorded_date = body.recorded_date || new Date().toISOString().split('T')[0];

// Use provided filename or derive one from the URL
let filename = body.filename || '';
if (!filename) {
  const url = body.file_url || body.transcript_url || '';
  filename = url.split('/').pop().split('?')[0] || (type + '_' + Date.now());
}

const file_url = body.file_url || '';           // video URL for AssemblyAI
const transcript_url = body.transcript_url || ''; // text file URL to fetch

if (type === 'recording' && !file_url) {
  throw new Error('type=recording requires file_url');
}
if (type === 'transcript' && !transcript_url) {
  throw new Error('type=transcript requires transcript_url');
}

return [{
  json: {
    type,
    title,
    category,
    recorded_date,
    filename,
    file_url,
    transcript_url
  }
}];

// Merge fetched text back with metadata from Parse Input
const meta = $('Parse Input').item.json;
const fetchedText = $input.item.json.data || $input.item.json;

// httpRequest with responseFormat=text puts content in the body
const transcriptText = (typeof fetchedText === 'string')
  ? fetchedText
  : JSON.stringify(fetchedText);

return [{
  json: {
    type: meta.type,
    title: meta.title,
    category: meta.category,
    recorded_date: meta.recorded_date,
    filename: meta.filename,
    transcript_text: transcriptText.trim()
  }
}];

// Combine recording_id from DB with transcript text
const recordingId = $input.item.json.id;
const meta = $('Merge Transcript Text').item.json;

return [{
  json: {
    recording_id: recordingId,
    transcript_text: meta.transcript_text,
    assemblyai_job_id: ''
  }
}];

const row = $input.item.json;
return [{
  json: {
    transcript_id: row.id,
    recording_id: row.recording_id,
    recording_title: $('Merge Transcript Text').item.json.title,
    full_text: $('Merge Transcript Text').item.json.transcript_text,
    existing_topics: typeof row.existing_topics === 'string'
      ? JSON.parse(row.existing_topics)
      : (row.existing_topics || [])
  }
}];

const recordingId = $input.item.json.id;
const meta = $('Parse Input').item.json;
return [{
  json: {
    recording_id: recordingId,
    file_url: meta.file_url,
    title: meta.title
  }
}];

const result = $input.item.json;
const prepData = $('Prep AssemblyAI Request').item.json;

return [{
  json: {
    recording_id: prepData.recording_id,
    transcript_text: result.text || '',
    assemblyai_job_id: result.id || ''
  }
}];

const row = $input.item.json;
const prepData = $('Prep Transcript Insert (Video)').item.json;
return [{
  json: {
    transcript_id: row.id,
    recording_id: prepData.recording_id,
    recording_title: $('Parse Input').item.json.title,
    full_text: prepData.transcript_text,
    existing_topics: typeof row.existing_topics === 'string'
      ? JSON.parse(row.existing_topics)
      : (row.existing_topics || [])
  }
}];
